class PromptShield:
    """Multi-layer prompt injection and extraction prevention"""

    def __init__(self, config: LLMSecurityConfig):
        self.config = config
        self.compiled_patterns = [
            re.compile(p, re.IGNORECASE) for p in config.blocked_patterns
        ]

    def detect_injection_attempt(self, user_input: str) -> Dict[str, Any]:
        """Detect prompt injection attempts"""
        threats = []

        # Pattern-based detection
        for pattern in self.compiled_patterns:
            if pattern.search(user_input):
                threats.append({
                    'type': 'pattern_match',
                    'pattern': pattern.pattern,
                    'severity': 'high'
                })

        # Detect attempts to extract system prompt
        extraction_indicators = [
            'system prompt', 'initial instructions', 'original prompt',
            'base prompt', 'hidden instructions', 'meta prompt'
        ]
        for indicator in extraction_indicators:
            if indicator.lower() in user_input.lower():
                threats.append({
                    'type': 'extraction_attempt',
                    'indicator': indicator,
                    'severity': 'high'
                })

        # Detect role manipulation
        role_manipulation = [
            'you are now', 'act as if', 'pretend to be',
            'roleplay as', 'simulate being', 'behave like'
        ]
        for phrase in role_manipulation:
            if phrase.lower() in user_input.lower():
                threats.append({
                    'type': 'role_manipulation',
                    'phrase': phrase,
                    'severity': 'medium'
                })

        # Check for encoding tricks
        if self._has_encoding_tricks(user_input):
            threats.append({
                'type': 'encoding_bypass',
                'severity': 'high'
            })

        return {
            'is_safe': len(threats) == 0,
            'threats': threats,
            'risk_score': min(len(threats) * 0.3, 1.0)
        }

    def _has_encoding_tricks(self, text: str) -> bool:
        """Detect encoding-based bypass attempts"""
        # Check for unusual Unicode characters used to bypass filters
        suspicious_chars = [
            '\u200b',  # Zero-width space
            '\u200c',  # Zero-width non-joiner
            '\u200d',  # Zero-width joiner
            '\u2060',  # Word joiner
            '\ufeff',  # BOM
        ]
        return any(char in text for char in suspicious_chars)

    def sanitize_input(self, user_input: str) -> str:
        """Sanitize input while preserving legitimate content"""
        # Remove zero-width characters
        sanitized = user_input
        for char in ['\u200b', '\u200c', '\u200d', '\u2060', '\ufeff']:
            sanitized = sanitized.replace(char, '')

        # Normalize whitespace
        sanitized = ' '.join(sanitized.split())

        return sanitized[:self.config.max_input_tokens * 4]  # Rough char limit

class OutputFilter:
    """Filter LLM outputs to prevent information leakage"""

    def __init__(self, system_prompt: str):
        self.system_prompt = system_prompt
        self.system_prompt_hash = hashlib.sha256(system_prompt.encode()).hexdigest()

    def filter_output(self, output: str) -> Dict[str, Any]:
        """Check if output leaks sensitive information"""
        issues = []
        filtered_output = output

        # Check if output contains system prompt fragments
        if self._contains_system_prompt_leak(output):
            issues.append('system_prompt_leak')
            filtered_output = "[Response filtered: potential information leak detected]"

        # Check for training data regurgitation patterns
        if self._looks_like_training_data(output):
            issues.append('potential_training_data')

        # Check for internal instruction revelation
        internal_markers = [
            'my instructions are', 'i was told to', 'my system prompt',
            'i am programmed to', 'my initial prompt'
        ]
        for marker in internal_markers:
            if marker in output.lower():
                issues.append(f'instruction_leak:{marker}')
                filtered_output = "[Response filtered: internal information detected]"
                break

        return {
            'output': filtered_output,
            'filtered': len(issues) > 0,
            'issues': issues
        }

    def _contains_system_prompt_leak(self, output: str) -> bool:
        """Check if output contains significant portions of system prompt"""
        # Simple n-gram similarity check
        system_words = set(self.system_prompt.lower().split())
        output_words = set(output.lower().split())

        if len(system_words) == 0:
            return False

        overlap = len(system_words & output_words) / len(system_words)
        return overlap > 0.5

    def _looks_like_training_data(self, output: str) -> bool:
        """Detect potential training data memorization"""
        # Check for patterns that suggest verbatim training data
        patterns = [
            r'copyright \d{4}',
            r'all rights reserved',
            r'licensed under',
            r'\[\d+\]\s*http',  # Citation patterns
        ]
        return any(re.search(p, output, re.IGNORECASE) for p in patterns)

class QueryBehaviorAnalyzer:
    """Detect model extraction and distillation attempts"""

    def __init__(self, redis_client, window_seconds: int = 3600):
        self.redis = redis_client
        self.window = window_seconds

    def record_and_analyze(self, api_key: str, query: str, response: str) -> Dict[str, Any]:
        """Record query and analyze for extraction patterns"""
        timestamp = time.time()
        query_hash = hashlib.sha256(query.encode()).hexdigest()[:16]

        # Store query metadata
        query_data = json.dumps({
            'hash': query_hash,
            'length': len(query),
            'timestamp': timestamp
        })

        key = f"llm_queries:{api_key}"
        self.redis.zadd(key, {query_data: timestamp})
        self.redis.expire(key, self.window * 2)

        # Analyze patterns
        return self._analyze_patterns(api_key)

    def _analyze_patterns(self, api_key: str) -> Dict[str, Any]:
        """Analyze query patterns for extraction attempts"""
        key = f"llm_queries:{api_key}"

        # Get recent queries
        cutoff = time.time() - self.window
        recent_queries = self.redis.zrangebyscore(key, cutoff, '+inf')

        if len(recent_queries) < 10:
            return {'suspicious': False, 'reason': None}

        # Parse query data
        queries = [json.loads(q) for q in recent_queries]

        # Check for distillation patterns
        # High volume of similar-length queries suggests systematic extraction
        lengths = [q['length'] for q in queries]
        avg_length = sum(lengths) / len(lengths)
        variance = sum((l - avg_length) ** 2 for l in lengths) / len(lengths)

        # Low variance in query length is suspicious
        if variance < 100 and len(queries) > 50:
            return {
                'suspicious': True,
                'reason': 'systematic_querying',
                'confidence': 0.8
            }

        # Check query frequency (more than 2 per second sustained)
        if len(queries) > 100:
            time_span = queries[-1]['timestamp'] - queries[0]['timestamp']
            if time_span > 0 and len(queries) / time_span > 2:
                return {
                    'suspicious': True,
                    'reason': 'high_frequency_extraction',
                    'confidence': 0.9
                }

        return {'suspicious': False, 'reason': None}

