def chat_completion():
    start_time = time.time()
    api_key = g.api_key

    try:
        data = request.json
        if not data or 'messages' not in data:
            abort(400, description="Missing messages")

        user_message = data['messages'][-1].get('content', '')

        # Layer 1: Input sanitization
        sanitized_input = prompt_shield.sanitize_input(user_message)

        # Layer 2: Injection detection
        safety_check = prompt_shield.detect_injection_attempt(sanitized_input)

        if not safety_check['is_safe']:
            PROMPT_INJECTION_ATTEMPTS.labels(type=safety_check['threats'][0]['type']).inc()
            logger.warning(f"Prompt injection blocked: {api_key[:8]}... - {safety_check['threats']}")

            # Don't reveal detection to attacker
            return jsonify({
                'choices': [{
                    'message': {
                        'role': 'assistant',
                        'content': "I'm not able to help with that request."
                    }
                }]
            })

        # Layer 3: Behavior analysis
        behavior = behavior_analyzer.record_and_analyze(api_key, sanitized_input, "")

        if behavior['suspicious']:
            EXTRACTION_ATTEMPTS.labels(method=behavior['reason']).inc()
            logger.warning(f"Extraction attempt detected: {api_key[:8]}... - {behavior['reason']}")

            # Throttle suspicious users
            if behavior.get('confidence', 0) > 0.8:
                abort(429, description="Rate limit exceeded. Please try again later.")

        # Construct protected prompt
        protected_messages = [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": sanitized_input}
        ]

        # Call underlying LLM
        response = openai.ChatCompletion.create(
            model="gpt-4",
            messages=protected_messages,
            max_tokens=config.max_output_tokens,
            temperature=0.7
        )

        assistant_response = response['choices'][0]['message']['content']

        # Layer 4: Output filtering
        if config.enable_output_filtering:
            filter_result = output_filter.filter_output(assistant_response)

            if filter_result['filtered']:
                logger.warning(f"Output filtered: {filter_result['issues']}")
                assistant_response = filter_result['output']

        # Record latency
        REQUEST_LATENCY.observe(time.time() - start_time)

        return jsonify({
            'choices': [{
                'message': {
                    'role': 'assistant',
                    'content': assistant_response
                },
                'finish_reason': 'stop'
            }],
            'usage': {
                'prompt_tokens': response['usage']['prompt_tokens'],
                'completion_tokens': response['usage']['completion_tokens']
            }
        })

    except openai.error.RateLimitError:
        abort(429, description="Service temporarily unavailable")
    except Exception as e:
        logger.error(f"Chat completion error: {e}")
        abort(500, description="Internal error")

