// Defense Layer 1: Content classification before processing
class ContentSecurityAnalyzer {
  constructor() {
    this.suspiciousPatterns = [
      { pattern: /ignore\s+(all\s+)?(previous|above|prior)\s+(instructions|rules|prompts)/gi, severity: 'critical' },
      { pattern: /you\s+are\s+(now\s+)?a?n?\s*(different|new|evil|unrestricted)/gi, severity: 'high' },
      { pattern: /\[\s*(SYSTEM|ADMIN|ROOT|INST)\s*\]/gi, severity: 'critical' },
      { pattern: /pretend\s+(you're|to\s+be|that)/gi, severity: 'medium' },
      { pattern: /\bexecute\b.*\b(code|command|function|script)\b/gi, severity: 'high' },
      { pattern: /reveal\s+(your|the|system)\s+(prompt|instructions|rules)/gi, severity: 'high' },
      { pattern: /<<\s*SYS\s*>>|<\|im_start\|>|\[INST\]/gi, severity: 'critical' },
      { pattern: /\bDAN\b|\bjailbreak\b|\bunfiltered\b/gi, severity: 'critical' }
    ];
  }

  analyzeContent(content, source) {
    const findings = [];
    let overallRisk = 'low';

    for (const { pattern, severity } of this.suspiciousPatterns) {
      const matches = content.match(pattern);
      if (matches) {
        findings.push({
          pattern: pattern.source,
          matches: matches.slice(0, 3),
          severity,
          source
        });

        if (severity === 'critical') overallRisk = 'critical';
        else if (severity === 'high' && overallRisk !== 'critical') overallRisk = 'high';
        else if (overallRisk === 'low') overallRisk = 'medium';
      }
    }

    return { findings, overallRisk, contentHash: this.hashContent(content) };
  }

  hashContent(content) {
    return crypto.createHash('sha256').update(content).digest('hex').substring(0, 16);
  }
}

