      'searchWeb': { perHour: 30, perDay: 100, requiresApproval: false }
    };
    this.actionCounts = new Map();
  }

  async validateAction(actionName, params, userId, context) {
    const limits = this.actionLimits[actionName];

    if (!limits) {
      logger.warn({ event: 'unknown_action_blocked', actionName, userId });
      return { allowed: false, reason: 'Unknown action type' };
    }

    // Check rate limits
    const userKey = `${userId}:${actionName}`;
    const counts = this.actionCounts.get(userKey) || { hourly: 0, daily: 0, lastReset: Date.now() };

    if (counts.hourly >= limits.perHour || counts.daily >= limits.perDay) {
      logger.warn({ event: 'rate_limit_exceeded', actionName, userId, counts });
      return { allowed: false, reason: 'Rate limit exceeded' };
    }

    // Validate parameters based on action type
    const paramValidation = this.validateParameters(actionName, params, limits);
    if (!paramValidation.valid) {
      return { allowed: false, reason: paramValidation.reason };
    }

    // Check if approval is required
    if (limits.requiresApproval) {
      const approvalId = crypto.randomUUID();
      this.pendingActions.set(approvalId, {
        actionName,
        params,
        userId,
        context,
        createdAt: Date.now(),
        expiresAt: Date.now() + 300000 // 5 minutes
      });

      logger.info({ event: 'action_pending_approval', approvalId, actionName, userId });

      return {
        allowed: false,
        requiresApproval: true,
        approvalId,
        message: `Action "${actionName}" requires your explicit confirmation. Reply with approval ID: ${approvalId}`
      };
    }

    // Update counts and allow
    counts.hourly++;
    counts.daily++;
    this.actionCounts.set(userKey, counts);

    return { allowed: true };
  }

  validateParameters(actionName, params, limits) {
    if (actionName === 'transferMoney') {
      if (params.amount > limits.maxAmount) {
        return { valid: false, reason: `Transfer amount exceeds limit of $${limits.maxAmount}` };
      }
      if (!params.recipient || !params.recipient.match(/^[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+$/)) {
        return { valid: false, reason: 'Invalid recipient format' };
      }
    }
    return { valid: true };
  }

  async approveAction(approvalId, userId) {
    const pending = this.pendingActions.get(approvalId);

    if (!pending || pending.userId !== userId) {
      return { success: false, reason: 'Invalid or expired approval' };
    }

    if (Date.now() > pending.expiresAt) {
      this.pendingActions.delete(approvalId);
      return { success: false, reason: 'Approval expired' };
    }

    this.pendingActions.delete(approvalId);

    logger.info({
      event: 'action_approved',
      approvalId,
      actionName: pending.actionName,
      userId
    });

    return { success: true, action: pending };
  }
}

