      name: (ctx.name || '').substring(0, 50),
      accountType: ['standard', 'premium'].includes(ctx.accountType) ? ctx.accountType : 'standard'
    });
  }

  buildUserMessage(directInput, externalContent = []) {
    let message = directInput;

    if (externalContent.length > 0) {
