// Main endpoint with all defenses
const contentProcessor = new SecureContentProcessor();
const actionGateway = new ActionGateway();
const promptBuilder = new SecurePromptBuilder();
const securityAnalyzer = new ContentSecurityAnalyzer();

app.post('/api/secure-assistant', async (req, res) => {
  const requestId = crypto.randomUUID();
  const { userMessage, userData, externalSources = [] } = req.body;
  const userId = userData?.userId;

  try {
    // Analyze direct user input
    const directAnalysis = securityAnalyzer.analyzeContent(userMessage, 'direct_input');

    // Process external content with full security analysis
    const processedExternal = [];
    for (const source of externalSources) {
      const analysis = securityAnalyzer.analyzeContent(source.content, source.type);

      logger.info({
        event: 'external_content_analyzed',
        requestId,
        source: source.type,
        riskLevel: analysis.overallRisk,
        findings: analysis.findings.length
      });

      // Block critical risk content entirely
      if (analysis.overallRisk === 'critical') {
        logger.warn({
          event: 'critical_content_blocked',
          requestId,
          source: source.type,
          findings: analysis.findings
        });
        continue; // Skip this content
      }

      // Sanitize and include with warning for high risk
      const sanitized = contentProcessor.sanitizeExternalContent(
        source.content,
        source.type
      );

      if (analysis.overallRisk === 'high') {
        processedExternal.push(
          `[WARNING: This content was flagged for potential manipulation]\n${sanitized}`
        );
      } else {
        processedExternal.push(sanitized);
      }
    }

    const response = await openai.chat.completions.create({
      model: 'gpt-4',
      messages: [
        { role: 'system', content: promptBuilder.buildSystemPrompt(userData) },
        { role: 'user', content: promptBuilder.buildUserMessage(userMessage, processedExternal) }
      ],
      functions: [
        { name: 'sendEmail', parameters: { type: 'object', properties: { to: { type: 'string' }, subject: { type: 'string' }, body: { type: 'string' } } } },
        { name: 'transferMoney', parameters: { type: 'object', properties: { amount: { type: 'number' }, recipient: { type: 'string' } } } },
        { name: 'readEmail', parameters: { type: 'object', properties: { emailId: { type: 'string' } } } }
      ]
    });

    const message = response.choices[0].message;

    // Gate any function calls
    if (message.function_call) {
      const actionName = message.function_call.name;
      const params = JSON.parse(message.function_call.arguments || '{}');

      const validation = await actionGateway.validateAction(
        actionName,
        params,
        userId,
        { requestId, directAnalysis }
      );

      if (!validation.allowed) {
        return res.json({
          requestId,
          response: validation.message || `Action blocked: ${validation.reason}`,
          requiresApproval: validation.requiresApproval,
          approvalId: validation.approvalId
        });
      }

      // Execute approved action
      logger.info({ event: 'action_executed', requestId, actionName, userId });
    }

    res.json({
      requestId,
      response: message.content,
      securityFlags: directAnalysis.overallRisk !== 'low' ? {
        riskLevel: directAnalysis.overallRisk,
        message: 'Some content was flagged for review'
      } : null
    });

  } catch (error) {
    logger.error({ event: 'request_error', requestId, error: error.message });
    res.status(500).json({ error: 'Internal error', requestId });
  }
});

