// Differential privacy implementation for probability outputs
class DifferentialPrivacy {
  constructor(epsilon = 1.0, sensitivity = 1.0) {
    this.epsilon = epsilon;
    this.sensitivity = sensitivity;
  }

  // Laplace mechanism for differential privacy
  laplaceMechanism(value) {
    const scale = this.sensitivity / this.epsilon;
    const u = Math.random() - 0.5;
    const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
    return value + noise;
  }

  // Apply differential privacy to probability distribution
  privatizeProbabilities(probabilities, tierEpsilon) {
    const epsilon = tierEpsilon || this.epsilon;
    const scale = this.sensitivity / epsilon;

    const noisy = probabilities.map(p => {
      const u = Math.random() - 0.5;
      const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
      return Math.max(0, p + noise);
    });

    // Renormalize to valid probability distribution
    const sum = noisy.reduce((a, b) => a + b, 0);
    return noisy.map(p => p / sum);
  }
}

const dp = new DifferentialPrivacy(1.0, 1.0);

// Tiered access with different privacy guarantees
const ACCESS_TIERS = {
  public: {
    maxQueries: 100,
    windowHours: 24,
