    maxDailyBudget: 100000,
    auditRequired: true
  }
};

// Privacy budget tracker - limits total information leakage
class PrivacyBudgetTracker {
  constructor(redis) {
    this.redis = redis;
  }

  async consumeBudget(userId, epsilon) {
    const key = `privacy_budget:${userId}:${new Date().toISOString().split('T')[0]}`;
    const current = parseFloat(await this.redis.get(key) || '0');
    const newBudget = current + (1 / epsilon); // Lower epsilon = higher cost

    await this.redis.setex(key, 86400, newBudget.toString());
    return newBudget;
  }

  async checkBudget(userId, maxBudget) {
    const key = `privacy_budget:${userId}:${new Date().toISOString().split('T')[0]}`;
    const current = parseFloat(await this.redis.get(key) || '0');
    return current < maxBudget;
  }
}

const budgetTracker = new PrivacyBudgetTracker(redis);

// Advanced extraction detection with long-term analysis
class ExtractionDetector {
  constructor(redis) {
    this.redis = redis;
  }

  async analyzeQueryPatterns(userId) {
    const patterns = {
      hourly: await this.getWindowStats(userId, 3600),
      daily: await this.getWindowStats(userId, 86400),
      weekly: await this.getWindowStats(userId, 604800)
    };

    const riskScore = this.calculateRiskScore(patterns);
    return { patterns, riskScore };
  }

  async getWindowStats(userId, windowSec) {
    const key = `queries:${userId}`;
    const now = Date.now();
    const cutoff = now - (windowSec * 1000);

    // Get queries in time window
    const queries = await this.redis.zrangebyscore(key, cutoff, now, 'WITHSCORES');

    if (queries.length < 2) return { count: queries.length / 2, diversity: 0, velocity: 0 };

    const hashes = [];
    for (let i = 0; i < queries.length; i += 2) {
      hashes.push(queries[i]);
    }

    const uniqueHashes = new Set(hashes).size;
    const diversity = uniqueHashes / hashes.length;
    const velocity = hashes.length / (windowSec / 3600); // queries per hour

    return { count: hashes.length, diversity, velocity };
  }

  calculateRiskScore(patterns) {
    let score = 0;

    // High diversity + high volume = likely extraction
    if (patterns.daily.diversity > 0.9 && patterns.daily.count > 500) {
      score += 40;
    }

    // Consistent velocity over long period = automated
    if (patterns.weekly.velocity > 10 && patterns.daily.velocity > 8) {
      score += 30;
    }

    // Unusual hourly patterns
    if (patterns.hourly.count > 50) {
      score += 20;
    }

    // Grid-like input patterns (covering feature space systematically)
    // This would require input analysis - simplified here

    return Math.min(100, score);
  }

  async recordQuery(userId, inputHash) {
    const key = `queries:${userId}`;
    await this.redis.zadd(key, Date.now(), inputHash);
    await this.redis.expire(key, 604800); // 7 day retention
  }
}

const detector = new ExtractionDetector(redis);

// Watermarking for outputs - enables tracing of leaked predictions
function addWatermark(probabilities, userId, timestamp) {
  const watermarkBits = crypto.createHash('sha256')
    .update(`${userId}:${timestamp}:${process.env.WATERMARK_SECRET}`)
    .digest();

  // Embed imperceptible watermark in least significant bits
  const watermarked = probabilities.map((p, i) => {
    const bit = (watermarkBits[i % 32] >> (i % 8)) & 1;
    const adjustment = bit ? 0.0001 : -0.0001;
    return p + adjustment;
  });

  return watermarked;
}

// Authentication middleware
async function authenticate(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    req.tier = ACCESS_TIERS.public;
    req.userId = req.ip;
    return next();
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.userId = decoded.sub;
    req.tier = ACCESS_TIERS[decoded.tier] || ACCESS_TIERS.public;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
}

app.post('/api/v2/predict', authenticate, async (req, res) => {
