    case 'top_class_only':
      const topIdx = probs.indexOf(Math.max(...probs));
      response = { prediction: topIdx };
      break;

    case 'top_k':
      const privatized = dp.privatizeProbabilities(probs, tier.epsilon);
      const indexed = privatized.map((p, i) => ({ class: i, prob: p }));
      indexed.sort((a, b) => b.prob - a.prob);
      response = {
        predictions: indexed.slice(0, tier.topK).map(x => ({
